import header from '../../css/header.css';


const Header = () => {
  return (
    <header>
        <h1><span className="$<header.red-text>">Dash</span>board</h1>
        <div className="searh_bar">
            <input type="text" placeholder="Search your task here..."/>
            <button><img src="/images/icons/search.svg" alt="search"/></button>
        </div>
        <button><img src="/images/icons/notification.svg" alt="notification"/></button>
        <button><img src="/images/icons/calender.svg" alt="calendar"/></button>

        <div className="date">
            <label>Tuesday</label>
            <label><span className="blue-text">20/06/2023</span></label>
        </div>
    </header>
  );
};

export default Header;
